async (globalVars) => {
  const response = globalVars.response;
 ; const prev = globalVars.extractData || [];
  const seenIds = new Set(prev.map(i => i.item_id));
  try {
    let body = (response.body || '').trim();
    if (typeof body === 'string' && body.startsWith('mtopjsonp')) {
    const m = body.match(/^mtopjsonp\d+\(([\s\S]*)\);?$/);
      if (m) body = m[1];
    }
    if (typeof body === 'string') {
      try { body = JSON.parse(body); } catch(e) { return [e]; }
    }
    if (body?.ret?.[0]?.includes('FAIL')) return [];
    const items = body?.data?.itemsArray || [];
    const results = [];
    for (const item of items) {
      if (!item.item_id || seenIds.has(String(item.item_id))) continue;
      seenIds.add(String(item.item_id));
      const ps = item.priceShow || {};
      const si = item.shopInfo || {};
      const title = (item.title || '').replace(/<[^>]+>/g, '').trim();
      results.push({
        rank: prev.length + results.length + 1,
        title: title.slice(0, 80),
        item_id: String(item.item_id),
        price: (ps.unit || '¥') + (ps.price || item.price || ''),
        realSales: item.realSales || '',
        shop: si.title || item.nick || '',
        procity: item.procity || '',
        isP4p: item.isP4p === 'true',
        url: 'https://item.taobao.com/item.htm?id=' + item.item_id,
        auctionUrl: item.auctionURL || ''
      });
    }
    return results;
  } catch (e) { return []; }
}
